// Extrae hallazgos accionables del resultado del servicio de analisis.
const r = $json;
const s = r.summary;
const revision = s.revision || {};
const grupos = (r.clusters || []).filter(c => c.es_grupo_consolidable);
const variantes = grupos.reduce((acc, c) => acc + c.miembros.length, 0);
const recomendaciones = r.recommendations || [];
const revisionItems = recomendaciones.filter(x => x.requiere_gate_gobierno);
const revisionIa = revision.asistida_ia ?? revisionItems.filter(x => x.revision_asistida_ia).length;
const manualProfunda = revision.manual_profunda ?? revisionItems.filter(x => x.revision_manual).length;
const objetivosPostApi = recomendaciones.reduce((acc, x) => {
  const destino = x.api_enablement?.destino_objetivo_post_habilitacion || x.destino;
  acc[destino] = (acc[destino] || 0) + 1;
  return acc;
}, {});
const rpaSelectivos = recomendaciones.filter(x => x.destino === 'rpa_selective');
const postN8n = rpaSelectivos.filter(x => x.api_enablement?.destino_objetivo_post_habilitacion === 'n8n').length;
const postCustom = rpaSelectivos.filter(x => x.api_enablement?.destino_objetivo_post_habilitacion === 'custom_python_java').length;
const ola3Items = recomendaciones.filter(x => x.ola === 'ola_3');
const complejidadExtrema = ola3Items.filter(x => x.complejidad > 85).length;
const menorValor = ola3Items.filter(x => x.complejidad <= 85 && x.valor < 50).length;
const gateGobiernoOla3 = ola3Items.filter(x => x.requiere_gate_gobierno).length;
const manualProfundaOla3 = ola3Items.filter(x => x.revision_manual).length;
const iaOla3 = ola3Items.filter(x => x.revision_asistida_ia).length;
const otros = ola3Items.length - complejidadExtrema - menorValor;
const ola3 = { total: ola3Items.length, complejidad_extrema: complejidadExtrema, menor_valor: menorValor, otros, gate_gobierno: gateGobiernoOla3, evaluacion_manual_profunda: manualProfundaOla3, asistida_ia: iaOla3 };
const sensibilidad = r.sensitivity ? { regla: r.sensitivity.regla, base: r.sensitivity.base, escenarios: r.sensitivity.escenarios || [] } : null;
let ola3Text = `${ola3.total} quedan en ola 3: ${complejidadExtrema} por complejidad extrema, ${menorValor} por menor valor`;
if (otros > 0) ola3Text += `, ${otros} por combinacion no prioritaria`;
if (gateGobiernoOla3 > 0) ola3Text += `. ${manualProfundaOla3} manual profunda y ${iaOla3} con IA/aprobacion dirigida`;
ola3Text += '.';
const headlines = [
  `${variantes} taskbots son variantes de ${grupos.length} utilidades reutilizables.`,
  `${s.por_destino.n8n} candidatos a n8n (integracion API/archivo/email).`,
  `${s.por_destino.rpa_selective} quedan en RPA selectivo o habilitacion API por UI legacy.`,
  `${postN8n + postCustom} RPA selectivos tienen destino objetivo post-habilitacion API (${postN8n} n8n, ${postCustom} Python/Java).`,
  `${s.por_destino.microservice} deberian ser microservicio/componente compartido.`,
  `${s.por_ola.ola_1} entran en ola 1 y ${s.por_ola.ola_2} en ola 2.`,
  `${revisionIa} gates se reducen con IA/aprobacion dirigida; ${manualProfunda} requieren evaluacion manual profunda.`,
  ola3Text
];
return [{ json: { run_id: r.run_id, headlines, resumen: s, revision, ola_3: ola3, destinos_objetivo_post_habilitacion: objetivosPostApi, sensibilidad } }];
